xpath.script:
                (function() {
                    var STORAGE_KEY = 'wl_page_agent_history';
                    var PENDING_TASK_KEY = 'wl_page_agent_pending_task';

                    // === Inject CSS AFTER page-agent loads ===
                    function injectCSS() {
                        if (document.getElementById('wl-pa-style')) return;
                        var style = document.createElement('style');
                        style.id = 'wl-pa-style';
                        style.textContent = `
[class*="_background_1tu05_"] {
    background: linear-gradient(135deg, rgba(90,8,14,0.97), rgba(122,12,20,0.97)) !important;
    border-radius: 12px !important;
    box-shadow: 0 8px 32px rgba(90,8,14,0.3) !important;
}
[class*="_historySectionWrapper_1tu05_"] { background: rgba(90,8,14,0.85) !important; }
[class*="_header_1tu05_"] { background: rgba(90,8,14,0.6) !important; }
[class*="_statusText_1tu05_"] { color: #f5c400 !important; font-weight: 600 !important; }
[class*="_indicator_1tu05_"] { background: #f5c400 !important; }
[class*="_inputSectionWrapper_1tu05_"] { background: rgba(253,251,245,0.95) !important; }
[class*="_taskInput_1tu05_"] {
    background: #fff !important; color: #1f1f1f !important;
    border: 1px solid #ddd !important; border-radius: 8px !important;
    font-size: 13px !important; padding: 8px 12px !important;
    font-family: Inter, -apple-system, sans-serif !important;
}
[class*="_taskInput_1tu05_"]:focus {
    border-color: #5a080e !important;
    box-shadow: 0 0 0 2px rgba(90,8,14,0.1) !important;
    outline: none !important;
}
[class*="_controlButton_1tu05_"]:not([class*="_stopButton"]) {
    background: rgba(245,196,0,0.15) !important;
    color: #f5c400 !important;
    border-radius: 6px !important;
}
[class*="_statusSection_1tu05_"] {
    display: flex !important; align-items: center !important; gap: 6px !important;
}
[class*="_historySection_1tu05_"]::-webkit-scrollbar { width: 4px !important; }
[class*="_historySection_1tu05_"]::-webkit-scrollbar-thumb {
    background: rgba(245,196,0,0.3) !important; border-radius: 4px !important;
}
                        `;
                        document.head.appendChild(style);
                    }

                    // === Fix Chinese text → Indonesian ===
                    function fixText() {
                        var input = document.querySelector('[class*="_taskInput_1tu05_"]');
                        if (input && input.placeholder && /[\u4e00-\u9fff]/.test(input.placeholder)) {
                            input.placeholder = 'Tulis perintah... (contoh: pesan seblak)';
                        }
                        var wrapper = document.querySelector('[class*="_wrapper_1tu05_"]');
                        if (!wrapper) return;
                        var walker = document.createTreeWalker(wrapper, NodeFilter.SHOW_TEXT, null);
                        var node;
                        while (node = walker.nextNode()) {
                            var t = node.textContent;
                            if (t.indexOf('\u51c6\u5907\u5c31\u7eea') >= 0) node.textContent = node.textContent.replace(/\u51c6\u5907\u5c31\u7eea/g, 'Siap');
                            if (t.indexOf('\u7b49\u5f85\u4efb\u52a1') >= 0) node.textContent = node.textContent.replace(/\u7b49\u5f85\u4efb\u52a1[^\n]*/g, 'Menunggu tugas...');
                            if (t.indexOf('\u6b63\u5728\u601d\u8003') >= 0) node.textContent = node.textContent.replace(/\u6b63\u5728\u601d\u8003[^\n]*/g, 'Sedang berpikir...');
                            if (t.indexOf('\u6b63\u5728\u6267\u884c') >= 0) node.textContent = node.textContent.replace(/\u6b63\u5728\u6267\u884c[^\n]*/g, 'Sedang menjalankan...');
                            if (t.indexOf('\u4efb\u52a1\u5b8c\u6210') >= 0) node.textContent = node.textContent.replace(/\u4efb\u52a1\u5b8c\u6210/g, 'Tugas selesai');
                            if (t.indexOf('\u4efb\u52a1\u5df2\u505c\u6b62') >= 0) node.textContent = node.textContent.replace(/\u4efb\u52a1\u5df2\u505c\u6b62/g, 'Tugas dihentikan');
                            if (t.indexOf('\u51fa\u73b0\u9519\u8bef') >= 0) node.textContent = node.textContent.replace(/\u51fa\u73b0\u9519\u8bef/g, 'Terjadi kesalahan');
                            if (t.indexOf('\u8f93\u5165\u65b0\u4efb\u52a1') >= 0) node.textContent = node.textContent.replace(/\u8f93\u5165\u65b0\u4efb\u52a1[^]*/g, 'Tulis perintah...');
                        }
                    }

                    // === Task state monitoring + persistence ===
                    var agentReady = false;
                    var taskWasActive = false;
                    var savedTaskInstruction = '';

                    function monitorTask(pa) {
                        // Poll task state every 300ms (faster to catch brief states)
                        setInterval(function() {
                            if (!pa || pa.disposed) return;

                            // Detect task state via indicator CSS class + statusText
                            // _thinking_ = actively working
                            // _completed_ = just finished (brief)
                            // no class / _error_ = idle
                            var indicator = document.querySelector('[class*="_indicator_1tu05_"]');
                            var indClass = indicator ? indicator.className : '';
                            var isThinking = indClass.indexOf('_thinking_') >= 0;
                            var isCompleted = indClass.indexOf('_completed_') >= 0;

                            if (isThinking) {
                                // Task is ACTIVE — save instruction
                                if (!taskWasActive) {
                                    taskWasActive = true;
                                    var instruction = pa.task || '';
                                    if (!instruction) {
                                        var input = document.querySelector('[class*="_taskInput_1tu05_\"]');
                                        if (input && input.value) instruction = input.value;
                                    }
                                    savedTaskInstruction = instruction;
                                    try { sessionStorage.setItem(PENDING_TASK_KEY, instruction); } catch(e) {}
                                    console.log('[Page Agent] Task active: ' + instruction.substring(0, 50));
                                }
                            } else if (taskWasActive) {
                                // Was active, now NOT thinking → task ended (completed or stopped)
                                // This catches _completed_ AND idle state (no special class)
                                taskWasActive = false;
                                savedTaskInstruction = '';
                                try { sessionStorage.removeItem(PENDING_TASK_KEY); } catch(e) {}
                                console.log('[Page Agent] Task ended (completed=' + isCompleted + '), cleared pending');
                            }

                            // Always save history
                            if (pa.history && pa.history.length > 0) {
                                try { sessionStorage.setItem(STORAGE_KEY, JSON.stringify(pa.history)); } catch(e) {}
                            }
                        }, 300);
                    }

                    // === Show resume dialog when pending task exists ===
                    function showResumeDialog(pa) {
                        var pending = sessionStorage.getItem(PENDING_TASK_KEY);
                        if (!pending) return;

                        console.log('[Page Agent] Found pending task: ' + pending.substring(0, 50));

                        // Remove any existing dialog
                        var existing = document.getElementById('wl-pa-resume-dialog');
                        if (existing) existing.remove();

                        // Build dialog
                        var overlay = document.createElement('div');
                        overlay.id = 'wl-pa-resume-dialog';
                        overlay.style.cssText = 'position:fixed;top:0;left:0;right:0;bottom:0;background:rgba(0,0,0,0.5);z-index:999999;display:flex;align-items:center;justify-content:center;font-family:Inter,-apple-system,sans-serif;';

                        var box = document.createElement('div');
                        box.style.cssText = 'background:#fff;border-radius:12px;padding:24px;max-width:400px;width:90%;box-shadow:0 8px 32px rgba(0,0,0,0.2);text-align:center;';

                        var icon = document.createElement('div');
                        icon.innerHTML = '🤖';
                        icon.style.cssText = 'font-size:32px;margin-bottom:12px;';

                        var title = document.createElement('h3');
                        title.textContent = 'Lanjutkan tugas?';
                        title.style.cssText = 'color:#5a080e;font-size:18px;font-weight:600;margin:0 0 8px 0;';

                        var desc = document.createElement('p');
                        desc.innerHTML = 'Ada tugas yang belum selesai:
' + pending.substring(0, 60) + (pending.length > 60 ? '...' : '') + '';
                        desc.style.cssText = 'color:#666;font-size:14px;line-height:22px;margin:0 0 20px 0;';

                        var btnRow = document.createElement('div');
                        btnRow.style.cssText = 'display:flex;gap:12px;justify-content:center;';

                        var btnDone = document.createElement('button');
                        btnDone.textContent = 'Sudah selesai';
                        btnDone.style.cssText = 'flex:1;padding:10px 16px;border:1px solid #ddd;background:#fff;color:#666;border-radius:8px;font-size:14px;font-weight:500;cursor:pointer;font-family:Inter,-apple-system,sans-serif;transition:all 0.2s;';
                        btnDone.onmouseenter = function() { this.style.background = '#f5f5f5'; };
                        btnDone.onmouseleave = function() { this.style.background = '#fff'; };

                        var btnResume = document.createElement('button');
                        btnResume.textContent = 'Lanjut';
                        btnResume.style.cssText = 'flex:1;padding:10px 16px;border:none;background:#f5c400;color:#5a080e;border-radius:8px;font-size:14px;font-weight:600;cursor:pointer;font-family:Inter,-apple-system,sans-serif;transition:all 0.2s;';
                        btnResume.onmouseenter = function() { this.style.background = '#e6b800'; };
                        btnResume.onmouseleave = function() { this.style.background = '#f5c400'; };

                        btnDone.onclick = function() {
                            sessionStorage.removeItem(PENDING_TASK_KEY);
                            overlay.remove();
                            console.log('[Page Agent] User chose: Sudah selesai. Pending cleared.');
                        };

                        btnResume.onclick = function() {
                            overlay.remove();
                            var task = sessionStorage.getItem(PENDING_TASK_KEY);
                            if (!task) return;
                            sessionStorage.removeItem(PENDING_TASK_KEY);

                            setTimeout(function() {
                                if (pa.disposed) {
                                    console.log('[Page Agent] Agent disposed, cannot resume');
                                    return;
                                }
                                console.log('[Page Agent] User chose: Lanjut. Resuming...');
                                pa.execute(task).then(function() {
                                    console.log('[Page Agent] Resume completed');
                                }).catch(function(e) {
                                    console.log('[Page Agent] Resume failed: ' + (e.message || e));
                                });
                            }, 500);
                        };

                        btnRow.appendChild(btnDone);
                        btnRow.appendChild(btnResume);
                        box.appendChild(icon);
                        box.appendChild(title);
                        box.appendChild(desc);
                        box.appendChild(btnRow);
                        overlay.appendChild(box);
                        document.body.appendChild(overlay);

                        console.log('[Page Agent] Resume dialog shown');
                    }

                    // === Main setup ===
                    function setupAgent() {
                        var pa = window.pageAgent;
                        if (!pa || pa.disposed) return false;

                        // 1. Set language
                        try {
                            pa.config.language = 'id-ID';
                            if (pa.config.pageController && pa.config.pageController.config) {
                                pa.config.pageController.config.language = 'id-ID';
                            }
                        } catch(e) {}

                        // 2. Restore chat history
                        try {
                            var saved = sessionStorage.getItem(STORAGE_KEY);
                            if (saved) {
                                var h = JSON.parse(saved);
                                if (Array.isArray(h) && h.length > 0) pa.history = h;
                            }
                        } catch(e) {}

                        // 3. Start task monitor
                        monitorTask(pa);

                        // 4. Save everything before page unload
                        window.addEventListener('beforeunload', function() {
                            try {
                                if (pa.task && pa.task !== '') {
                                    sessionStorage.setItem(PENDING_TASK_KEY, pa.task);
                                }
                                if (pa.history && pa.history.length > 0) {
                                    sessionStorage.setItem(STORAGE_KEY, JSON.stringify(pa.history));
                                }
                            } catch(e) {}
                        });

                        // 5. Show resume dialog if there's a pending task
                        setTimeout(function() {
                            showResumeDialog(pa);
                        }, 2000);

                        return true;
                    }

                    // === Init loop ===
                    var attempts = 0;
                    var interval = setInterval(function() {
                        attempts++;
                        injectCSS();
                        fixText();
                        if (window.pageAgent && !window.pageAgent.disposed) {
                            if (!agentReady) {
                                if (setupAgent()) {
                                    agentReady = true;
                                    console.log('[Page Agent] Warung Lakku AI ready (styled, Indonesian, auto-resume enabled)');
                                }
                            }
                        }
                        if (attempts >= 120) clearInterval(interval);
                    }, 500);

                    // MutationObserver: fix text on DOM changes
                    var observer = new MutationObserver(function() {
                        fixText();
                    });
                    if (document.body) {
                        observer.observe(document.body, { childList: true, subtree: true, characterData: true });
                    }
                })();
